import React from 'react';
import './Main.css';

const tickerItems = ['Agent', 'LLM', 'MCP', 'Network', 'API', 'Identity', 'Access', 'Visibility'];

const Main = () => {
  return (
    <>
      <section className="main-hero">
        <div className="hero-content">
          <p className="hero-subtitle">Safe AI Adoption on Critical Infrastructure with</p>
          <h1 className="hero-title">AGENTIC DEFENSIVE AI SECURITY</h1>
        </div>
      </section>
      <section className="section-white">
        <div className="ticker-container">
          <div className="ticker-track">
            {[...tickerItems, ...tickerItems, ...tickerItems].map((item, index) => (
              <div key={index} className="ticker-item">
                <span className="ticker-icon">+</span>
                <span className="ticker-text">{item}</span>
              </div>
            ))}
          </div>
        </div>
      </section>
    </>
  );
};

export default Main;
